import signal
import pytest
from source import bitcount


def _timeout_handler(signum, frame):
    raise TimeoutError("bitcount did not terminate — infinite loop detected")


def test_bitcount_terminates_and_counts_127():
    signal.signal(signal.SIGALRM, _timeout_handler)
    signal.alarm(2)
    try:
        result = bitcount(127)
    except TimeoutError:
        pytest.fail(
            "bitcount(127) looped forever; XOR assignment never clears the lowest set bit"
        )
    finally:
        signal.alarm(0)

    assert result == 7, (
        f"bitcount(127) should return 7 (seven 1-bits in 0b1111111), got {result}"
    )
